// Parse and deduplicate signals from all RSS sources
const allItems = $input.all();
const seen = new Set();
const signals = [];

for (const item of allItems) {
  const title = item.json.title || '';
  const link = item.json.link || '';
  const pubDate = item.json.pubDate || '';

  // Deduplicate by title similarity
  const titleKey = title.toLowerCase().replace(/[^a-z0-9]/g, '').substring(0, 50);
  if (seen.has(titleKey)) continue;
  seen.add(titleKey);

  // Classify signal type
  let signalType = 'general';
  let signalStrength = 'low';
  const titleLower = title.toLowerCase();

  if (titleLower.includes('prior auth') || titleLower.includes('revenue cycle') || titleLower.includes('hiring')) {
    signalType = 'pain_signal';
    signalStrength = 'high';
  } else if (titleLower.includes('expansion') || titleLower.includes('new location') || titleLower.includes('opens')) {
    signalType = 'expansion';
    signalStrength = 'high';
  } else if (titleLower.includes('ehr') || titleLower.includes('epic') || titleLower.includes('cerner') || titleLower.includes('migration')) {
    signalType = 'ehr_migration';
    signalStrength = 'medium';
  } else if (titleLower.includes('automation') || titleLower.includes('ai') || titleLower.includes('digital')) {
    signalType = 'tech_adoption';
    signalStrength = 'medium';
  }

  // Extract organization name (heuristic: first proper noun phrase)
  const orgMatch = title.match(/([A-Z][a-zA-Z]+(?:\s+[A-Z][a-zA-Z]+){0,4})\s+(?:Health|Medical|Clinic|Hospital|Group|Care|Partners)/i);
  const orgName = orgMatch ? orgMatch[0] : 'NEEDS_MANUAL_REVIEW';

  signals.push({
    json: {
      signal_id: `SIG-${Date.now()}-${signals.length}`,
      org_name: orgName,
      signal_type: signalType,
      signal_strength: signalStrength,
      headline: title,
      source_url: link,
      detected_at: new Date().toISOString(),
      published_at: pubDate,
      status: 'new'
    }
  });
}

return signals;
